verilated.h holds the definition of `VL_CONSTHI_W_1X` 
```cpp
// verilated.h
typedef vluint32_t* WDataOutP;
#define VL_EDATASIZE 32
#define VL_WORDS_I(nbits) (((nbits) + (VL_EDATASIZE - 1)) / VL_EDATASIZE)

#define _END(obits, wordsSet) \
    for (int i = (wordsSet); i < VL_WORDS_I(obits); ++i) o[i] = 0; \
    return o

static inline WDataOutP VL_CONSTHI_W_1X(int obits, int lsb, WDataOutP obase,
                                        EData d0) VL_MT_SAFE {
    WDataOutP o = obase + VL_WORDS_I(lsb);
    o[0] = d0;
    _END(obits,1); // Note: In this case, o[0] = obase + 32, and _END() iterates another 32 times;
                           // I think it should be _END(obits - lsb, 1);
                           // Same as other VL_CONSTHI_W_?X functions.
}

